<template>
  <div>
    <HeroHeaderDashboard :title="title" :breadcrumbs="breadcrumbs" />
    <BoxContent>
      <template #content>
        <BoxInformation title="Editar pack" :columns="1">
          <FormPackDashboard :pack="pack" @saved="handlePackSaved" />
        </BoxInformation>
      </template>
      <template #sidebar>
        <BoxInformation title="Detalles" :columns="1">
          <CardInfoDashboard
            v-if="pack"
            title="Fecha de creación"
            :description="formatDate(pack.createdAt)"
          />
          <CardInfoDashboard
            v-if="pack"
            title="Última modificación"
            :description="formatDate(pack.updatedAt)"
          />
        </BoxInformation>
      </template>
    </BoxContent>
  </div>
</template>

<script setup lang="ts">
import { ref, computed } from "vue";
import { useRoute } from "vue-router";
import type { PackData } from "@/components/FormPackDashboard.vue";
import { formatDate } from "@/utils/date";

definePageMeta({
  layout: "dashboard",
});

const route = useRoute();
const pack = ref<
  (PackData & { createdAt?: string; updatedAt?: string; name?: string }) | null
>(null);
const apiClient = useApiClient();

const title = computed(() => pack.value?.name || "Pack");
const breadcrumbs = computed(() => [
  { label: "Packs", to: "/dashboard/maintenance/packs" },
  ...(pack.value?.name
    ? [
        {
          label: pack.value.name,
          to: `/dashboard/maintenance/packs/${route.params.id}`,
        },
      ]
    : []),
  { label: "Editar" },
]);

const handlePackSaved = (updatedPack: PackData) => {
  if (updatedPack) {
    pack.value = updatedPack;
  }
};

const { data: packData } = await useAsyncData(
  `pack-edit-${route.params.id}`,
  async () => {
    const id = route.params.id;
    if (!id) return null;

    const response = (await apiClient("ad-packs", {
      method: "GET",
      params: { filters: { documentId: { $eq: id } } } as unknown as Record<
        string,
        unknown
      >,
    })) as { data: unknown[] };
    const data = Array.isArray(response.data) ? response.data[0] : null;
    if (data) return data;

    const fallback = (await apiClient(`ad-packs/${id}`, { method: "GET" })) as {
      data: unknown;
    };
    return (fallback.data as unknown) || null;
  },
);

pack.value =
  (packData.value as
    | (PackData & { createdAt?: string; updatedAt?: string; name?: string })
    | null) ?? null;
</script>
